package pl.rezerwacjasal.rezerwacjasal.service; import java.math.BigDecimal; import java.time.*; import java.util.*; import org.springframework.stereotype.Service; import jakarta.transaction.Transactional; import lombok.RequiredArgsConstructor; import pl.rezerwacjasal.rezerwacjasal.model.*; import pl.rezerwacjasal.rezerwacjasal.repository.*; @Service @RequiredArgsConstructor @Transactional public class RoomReservationService { private final ConferenceRoomRepository roomRepository; private final RoomReservationRepository reservationRepository; private final AppUserService appUserService; public BigDecimal calculatePrice(ConferenceRoom room, LocalDateTime start, LocalDateTime end) { validate(start,end); long hours=Math.max(1, Duration.between(start,end).toHours()); return room.getPricePerHour().multiply(BigDecimal.valueOf(hours)); } public RoomReservation createReservation(Long roomId, LocalDateTime start, LocalDateTime end) { validate(start,end); ConferenceRoom room=roomRepository.findById(roomId).orElseThrow(() -> new RuntimeException("Room not found")); boolean occupied=reservationRepository.findAll().stream().anyMatch(r -> r.getRoom().getId().equals(roomId) && r.getStartTime().isBefore(end) && r.getEndTime().isAfter(start)); Optional.of(occupied).filter(v -> !v).orElseThrow(() -> new IllegalStateException("Room occupied")); RoomReservation r=new RoomReservation(); r.setRoom(room); r.setUser(appUserService.getLoggedInUser()); r.setStartTime(start); r.setEndTime(end); r.setTotalPrice(calculatePrice(room,start,end)); return reservationRepository.save(r); } public List<ConferenceRoom> getAllRooms() { return roomRepository.findAll(); } public List<RoomReservation> getMine() { AppUser user=appUserService.getLoggedInUser(); return reservationRepository.findAll().stream().filter(r -> r.getUser().getId().equals(user.getId())).toList(); } public List<RoomReservation> getAll() { return reservationRepository.findAll(); } public List<RoomReservation> getSchedule(Long roomId) { return reservationRepository.findAll().stream().filter(r -> r.getRoom().getId().equals(roomId)).sorted(Comparator.comparing(RoomReservation::getStartTime)).toList(); } private void validate(LocalDateTime start, LocalDateTime end) { Optional.ofNullable(start).filter(s -> end != null).filter(s -> !s.isBefore(LocalDateTime.now())).filter(s -> s.isBefore(end)).orElseThrow(() -> new IllegalArgumentException("Wrong dates")); } }
